from crewai import Agent, Task, Crew
from tiktoken import get_encoding

encoding = get_encoding('cl100k_base')

class TokenMonitor:
    def __init__(self, model_limit=128000):
        self.model_limit = model_limit
        self.threshold = model_limit * 0.8

    def check_context(self, task, agent):
        # Simulate context accumulation
        context = task.description + agent.goal + str(task.context.get('history', ''))
        tokens = len(encoding.encode(context))
        if tokens > self.threshold:
            print(f'⚠️  {agent.role}: {tokens} tokens ({tokens/self.model_limit*100:.1f}%)')
            return False
        return True

token_monitor = TokenMonitor()

# Usage in crew
def monitored_execute(crew):
    for task in crew.tasks:
        if not token_monitor.check_context(task, task.agent):
            raise ValueError('Context window overflow detected')
    return crew.kickoff()

from crewai import Crew
from collections import defaultdict, deque

class DelegationLoopDetector:
    def __init__(self, max_handoffs=10):
        self.max_handoffs = max_handoffs
        self.delegation_chains = defaultdict(deque)

    def track_delegation(self, from_agent, to_agent, context_size):
        chain_key = f'{from_agent.role}->{to_agent.role}'
        self.delegation_chains[chain_key].append(context_size)

        if len(self.delegation_chains[chain_key]) > self.max_handoffs:
            avg_size = sum(self.delegation_chains[chain_key]) / len(self.delegation_chains[chain_key])
            if avg_size > 50000:  # Growing context
                print(f'🔄 Loop detected: {chain_key} avg {avg_size:.0f} tokens')
                return False
        return True

# Global detector
detector = DelegationLoopDetector()

# In CrewAI callback
def on_task_complete(task, context_size):
    if hasattr(task, 'previous_agent'):
        return detector.track_delegation(task.previous_agent, task.agent, context_size)

