from crewai import Agent, Task
from langchain.prompts import PromptTemplate
from langchain.llms import OpenAI

summarizer = OpenAI(temperature=0)
SUMMARY_PROMPT = """
Summarize the key decisions, context, and unresolved issues from this conversation:
{conversation}

Keep under 1000 tokens. Focus on:
1. Original objectives
2. Key findings/decisions
3. Pending actions
4. Context for next agent

Summary:
"""

class ContextManager:
    def summarize_context(self, full_history: str, max_tokens=4000):
        if len(full_history) < max_tokens:
            return full_history

        prompt = SUMMARY_PROMPT.format(conversation=full_history[-8000:])
        summary = summarizer(prompt)
        return f'SUMMARY:\n{summary}\n\nRECENT:{full_history[-2000:]}'

# Integrate with CrewAI tasks
class ManagedTask(Task):
    def prepare_context(self):
        if 'history' in self.context:
            self.context['history'] = ContextManager().summarize_context(
                self.context['history']
            )
        return super().prepare_context()

from crewai import Crew
from typing import Dict, List

class HierarchicalContext:
    def __init__(self):
        self.layers = {
            'summary': '',      # 500 tokens
            'recent': '',       # 2000 tokens
            'full': []          # List of compressed chunks
        }

    def add_message(self, message: str, agent_role: str):
        # Always keep recent
        self.layers['recent'] += f'{agent_role}: {message}\n'
        self.layers['recent'] = self.layers['recent'][-4000:]

        # Update summary every 3 messages
        if len(self.layers['full']) % 3 == 0:
            self.update_summary()

    def update_summary(self):
        summary = self.summarize(self.layers['recent'])
        self.layers['summary'] = summary
        self.layers['full'].append({
            'chunk': summary,
            'tokens': len(summary)
        })

    def get_context_for_agent(self, max_tokens=8000) -> str:
        context = self.layers['summary'] + '\n\n' + self.layers['recent']
        return context[-max_tokens:]

# CrewAI integration
context_store = HierarchicalContext()

crew = Crew(
    agents=[...],
    tasks=[...],
    context={'shared_context': context_store}
)

def task_callback(task):
    context_store.add_message(task.output, task.agent.role)
    task.context = context_store.get_context_for_agent()
